        content = reader.ReadBytes(itemLinkDataCount);
    }

    public void Write(BinaryWriter writer)
    {
        writer.Write(itemLinkDataCount);
        receiver.Write(writer);
        writer.Write(len);
        writer.Write(content);
    }
}

